const chatId  = $('Telegram Trigger').first().json.message.chat.id;

// Передаём публичный Supabase URL напрямую — OpenAI скачивает изображение сам.
// base64 не используем: n8n хранит бинарные данные на диске (filesystem-v2),
// Code-нода в task runner не может их прочитать.
const planUrl = `https://phnjdyuwtsqqteyqetgm.supabase.co/storage/v1/object/public/bti-files/plans/${chatId}/plan.png`;

const prompt = `Ты — эксперт по анализу планов БТИ. Проанализируй план квартиры.
Верни ТОЛЬКО чистый JSON (без markdown, без пояснений) в точно таком формате:
{
  "rooms": [
    {
      "id": "room_1",
      "name": "Жилая комната 1",
      "region_percent": { "x1": 0.05, "y1": 0.10, "x2": 0.45, "y2": 0.55 }
    }
  ],
  "shots": [
    {
      "shot_id": "room_1_shot_1",
      "room_id": "room_1",
      "room_name": "Жилая комната 1",
      "position": "северо-западный угол",
      "direction": "на юго-восток",
      "instruction": "Встаньте в угол комнаты и сфотографируйте всё помещение целиком"
    }
  ]
}
Правила:
- Найди все помещения: жилые комнаты, кухня, санузел(ы), коридор, балкон/лоджия, кладовая
- Для каждого помещения: 1-2 точки съёмки (угол охвата >= 120 градусов)
- Инструкции конкретные: с какой точки, куда смотреть
- Все тексты на русском языке
- region_percent: нормализованные координаты 0.0-1.0`;

const requestBody = {
  model: "gpt-4o-mini",
  messages: [
    {
      role: "user",
      content: [
        { type: "text", text: prompt },
        { type: "image_url", image_url: { url: planUrl, detail: "high" } }
      ]
    }
  ],
  response_format: { type: "json_object" },
  temperature: 0.1,
  max_tokens: 4096
};

return [{ json: { chatId, requestBodyString: JSON.stringify(requestBody) } }];

const resp   = $input.first().json;
const chatId = $('Code - Gemini Request').first().json.chatId;

let parsed;
try {
  const text = resp.choices[0].message.content;
  parsed = JSON.parse(text);
} catch(e) {
  throw new Error('Ошибка разбора ответа GPT: ' + e.message);
}

const rooms = parsed.rooms || [];
const shots = parsed.shots || [];

const shotsStatus = {};
shots.forEach(s => { shotsStatus[s.shot_id] = 'pending'; });

const firstShot = shots[0];
if (!firstShot) throw new Error('GPT не вернул точки съёмки');
shotsStatus[firstShot.shot_id] = 'requested';

const roomsList = rooms.map(r => '• ' + r.name).join('
');
const roomsText = '*План проанализирован!*

Обнаруженные помещения:
' + roomsList + '

Всего точек съёмки: ' + shots.length;

const total    = shots.length;
const firstMsg = '📷 *Фото 1 из ' + total + '*

🏠 ' + firstShot.room_name + '
📍 Позиция: ' + firstShot.position + '
➡️ Направление: ' + firstShot.direction + '

' + firstShot.instruction + '

_Отправьте фото как документ/файл — это сохраняет качество_';

return [{
  json: {
    chatId,
    rooms_json:        rooms,
    shots_json:        shots,
    shots_status:      shotsStatus,
    rooms_text:        roomsText,
    first_instruction: firstMsg,
    total_shots:       total
  }
}];

const session = $('Get a row1').first().json;
const chatId  = $('Telegram Trigger').first().json.message.chat.id;

const shotsStatus = typeof session.shots_status === 'string'
  ? JSON.parse(session.shots_status) : (session.shots_status || {});
const shots = typeof session.shots_json === 'string'
  ? JSON.parse(session.shots_json) : (session.shots_json || []);

const requestedShotId = Object.keys(shotsStatus).find(id => shotsStatus[id] === 'requested');
if (!requestedShotId) {
  throw new Error('Нет активной точки съёмки. Введите /start для перезапуска.');
}

const updatedStatus = { ...shotsStatus };
updatedStatus[requestedShotId] = 'received';

const nextShot = shots.find(s => updatedStatus[s.shot_id] === 'pending');
const allDone  = !nextShot;
let nextStatus = { ...updatedStatus };
let nextMessage = '';

if (!allDone) {
  nextStatus[nextShot.shot_id] = 'requested';
  const total     = shots.length;
  const shotIndex = shots.findIndex(s => s.shot_id === nextShot.shot_id) + 1;
  nextMessage = '📷 *Фото ' + shotIndex + ' из ' + total + '*

🏠 ' + nextShot.room_name + '
📍 Позиция: ' + nextShot.position + '
➡️ Направление: ' + nextShot.direction + '

' + nextShot.instruction + '

_Отправьте фото как документ/файл — это сохраняет качество_';
} else {
  nextMessage = '✅ Все фотографии получены!

Начинаю финальный анализ перепланировки. Это займёт 1-2 минуты...';
}

// Pass binary through so HTTP Request - Upload Photo can upload the file
return [{
  json: {
    chatId,
    current_shot_id: requestedShotId,
    shots_status:    nextStatus,
    all_done:        allDone,
    next_message:    nextMessage,
    upload_path:     'photos/' + chatId + '/' + requestedShotId + '.jpg'
  },
  binary: items[0].binary
}];

// Binary data is received from HTTP Request - Download Plan node
// n8n stores binary as base64 in item.binary[key].data
const binary = $input.first().binary;
const key = Object.keys(binary)[0];
const base64 = binary[key].data;
const mimeType = binary[key].mimeType || 'image/jpeg';

if (!base64) throw new Error('Binary data is empty — plan not found in Supabase');

return [{ json: { base64, mimeType } }];

// Загрузи эти PDF в Supabase Storage: bti-files/knowledge-base/
// normy.pdf   → Чек лист нормы перепланировок
// katalog.pdf → Каталог типовых решений перепланировок
// razmery.pdf → Чек лист допустимые размеры помещений
return [
  { json: { path: 'knowledge-base/normy.pdf',   source: 'Чек лист нормы перепланировок' } },
  { json: { path: 'knowledge-base/katalog.pdf',  source: 'Каталог типовых решений перепланировок' } },
  { json: { path: 'knowledge-base/razmery.pdf',  source: 'Чек лист допустимые размеры помещений' } }
];

const text   = $input.first().json.text || '';
const source = $('Code - PDF Sources').item?.json?.source || 'unknown';

const MAX_CHARS = 80000;
const truncated = text.length > MAX_CHARS
  ? text.substring(0, MAX_CHARS) + '\n[текст обрезан]'
  : text;

const userMessage = `Ты — эксперт по российскому жилищному законодательству.
Тебе дан текст нормативного документа: "${source}".

Раздели текст на смысловые блоки по правилам:
- Каждый блок = одна статья, пункт, подпункт или логически завершённый раздел
- НЕ режь по страницам — только по смысловым границам
- Каждый блок должен быть самодостаточным (понятен без контекста)
- Минимум: 3 предложения. Максимум: ~500 слов.

Верни ТОЛЬКО валидный JSON объект, без markdown:
{"chunks": [{"title": "номер/заголовок пункта", "chunk": "полный текст блока"}]}

Текст документа:
${truncated}`;

// Cohere Chat v2 request format
const body = {
  model: 'command-r-plus-08-2024',
  messages: [{ role: 'user', content: userMessage }],
  response_format: { type: 'json_object' },
  temperature: 0.1
};

return [{ json: { source, requestBody: JSON.stringify(body) } }];

const resp   = $input.first().json;
const source = $('Code - Prep Chunking Request').item?.json?.source || 'unknown';

let chunks = [];
try {
  // Cohere v2: resp.message.content[0].text
  const raw = resp.message?.content?.[0]?.text || resp.text || '';
  const parsed = JSON.parse(raw);
  chunks = parsed.chunks || parsed.items || (Array.isArray(parsed) ? parsed : []);
} catch(e) {
  throw new Error('Ошибка парсинга ответа Cohere: ' + e.message);
}

if (!chunks.length) throw new Error('Cohere вернул пустой список чанков для: ' + source);

console.log(`Источник: ${source} — чанков: ${chunks.length}`);

return chunks.map((c, i) => ({
  json: {
    source,
    title: c.title || `Блок ${i + 1}`,
    chunk: c.chunk || c.text || c.content || '',
    index: i
  }
}));

const embResp = $input.first().json;
// Cohere v2 embeddings: { embeddings: { float: [[...1024 floats...]] } }
const embedding = embResp.embeddings?.float?.[0];
if (!embedding) throw new Error('Cohere не вернул embedding: ' + JSON.stringify(embResp).substring(0, 200));

const chunkData = $('Code - Parse Chunks').item.json;

return [{
  json: {
    source:    chunkData.source,
    chunk:     chunkData.chunk,
    embedding: embedding    // 1024-dimensional float array
  }
}];
